/* Changelog — single source of truth for the in-app "What's new" modal.
   Newest first; add a new entry on top each release. Bullets are localized. */
const CHANGELOG = [
  { v:'2.4.0', date:'2026-06-22',
    en:['Practice\'s Rhythm section is now complete with three new coach drills you play along with over the backing band.',
        'Strumming patterns: common down/up patterns loop over your chord on an eighth-note grid, lit slot-by-slot in time — see it, hear it, strum along.',
        'Comp the progression: a progression cycles with bass and drums while a big NOW chord and a NEXT preview land each change in time. Groove & feel: loop a one-bar groove and toggle swing, the backbeat accent and palm-muting to feel what makes it sit right.',
        'New accessibility options in Settings: a colour-blind-safe palette and a distinct shape for each note role (root, third, fifth, seventh), so the fretboard reads without relying on colour alone.',
        'A short welcome now greets first-time visitors with the three ways in — Reference, Practice and Ear.'],
    uk:['Розділ «Ритм» у «Практиці» тепер повний — три нові коуч-вправи, які граєш разом із гуртом супроводу.',
        'Малюнки боя: поширені удари вниз/вгору крутяться над твоїм акордом по сітці восьмих, підсвічуючись клітинка за клітинкою в темп — бачиш, чуєш і граєш разом.',
        'Акомпанемент прогресії: прогресія крутиться з басом і ударними, а великий акорд «Зараз» і прев’ю «Далі» допомагають вчасно змінювати акорди. Грув і відчуття: зацикли однотактовий грув і вмикай свінг, бекбіт-акцент та глушіння, щоб відчути, що робить грув живим.',
        'Нові опції доступності в «Налаштуваннях»: палітра для дальтоніків і окрема форма для кожної ролі ноти (тоніка, терція, квінта, септима), щоб гриф читався без опори лише на колір.',
        'Новачків тепер вітає коротке віконце з трьома способами почати — «Довідник», «Практика» та «Слух».'] },
  { v:'2.3.0', date:'2026-06-21',
    en:['Practice now has a Rhythm section, starting with the classic "one-minute changes" — the most useful drill there is for getting your chord changes clean and fast.',
        'Pick a chord pair (A–D, C–G, G–Em and more), choose 30/60/90 seconds, and switch between the two shapes as cleanly as you can. The two chord diagrams stay on screen the whole time so you always know where your fingers go.',
        'Tap the big button on every clean change; at the end you get your changes-per-minute and your personal best for that pair, so there is always a record to beat. An optional metronome gives you a pulse to switch against.',
        'Honest by design: this is a coach drill — it counts your taps, not your guitar. Real "play it and get scored" lands later with microphone input.'],
    uk:['У «Практиці» зʼявився розділ «Ритм», і перша вправа — класична «зміна акордів за хвилину», найкорисніше, що є для чистих і швидких переходів між акордами.',
        'Обери пару акордів (A–D, C–G, G–Em та інші), задай 30/60/90 секунд і перемикайся між двома формами якомога чистіше. Обидві аплікатури весь час на екрані, тож завжди видно, куди ставити пальці.',
        'Натискай велику кнопку на кожній чистій зміні; наприкінці отримуєш кількість змін за хвилину й свій рекорд для цієї пари — завжди є що побити. За бажання вмикається метроном для пульсу.',
        'Чесно за задумом: це коуч-вправа — вона рахує твої натискання, а не звук гітари. Справжня оцінка гри зʼявиться згодом, із мікрофоном.'] },
  { v:'2.2.0', date:'2026-06-21',
    en:['Sound is now in stereo. The guitar spreads across the stereo field by register — low strings centred, higher strings wider — so chords and scales open up instead of collapsing to one spot, and the hi-hats sit slightly off-centre like a real kit.',
        'A master Volume slider in the Backing panel sets the overall output level (and is remembered between visits).',
        'A built-in tuner: tap a string in Settings to hold its reference pitch and tune a real guitar by ear — it follows your current tuning, so Drop D and the others re-label automatically. No microphone needed.',
        'A final limiter now guards the output, so loud volumes or dense extended chords no longer clip.'],
    uk:['Звук тепер стерео. Гітара розкладається в стереополі за регістром — низькі струни в центрі, вищі ширше — тож акорди й гами розкриваються, а не збираються в одну точку; хай-хети ж сидять трохи збоку, як у справжній установці.',
        'Повзунок гучності у панелі «Супровід» задає загальний рівень виходу (і памʼятається між візитами).',
        'Вбудований тюнер: натисни струну в «Налаштуваннях», щоб утримати її еталонну висоту й налаштувати справжню гітару на слух — він іде за поточним строєм, тож Drop D та інші перепозначаються автоматично. Мікрофон не потрібен.',
        'Фінальний лімітер тепер береже вихід, тож гучні рівні чи насичені розширені акорди більше не перевантажуються.'] },
  { v:'2.1.0', date:'2026-06-21',
    en:['Euterpe now has Ear training — a new mode beside Reference and Practice (in the bottom bar on a phone) with three by-ear drills.',
        'Intervals by ear: hear two notes and name the interval, from a minor 2nd up to the octave.',
        'Chord quality by ear: hear a chord and tell major from minor, diminished, augmented and the four common sevenths.',
        'Rhythm by ear: hear a one-bar figure played over a soft beat and pick the matching rhythm.',
        'Every ear drill is scored on accuracy and feeds the same progress tracking as the fretboard drill — the notes and intervals you miss come back around.'],
    uk:['У Euterpe зʼявилося тренування слуху — новий режим поряд із «Довідником» і «Практикою» (на телефоні — у нижній смужці) із трьома вправами на слух.',
        'Інтервали на слух: почуй дві ноти й назви інтервал — від малої секунди до октави.',
        'Якість акорду на слух: почуй акорд і відрізни мажор від мінору, зменшеного, збільшеного та чотирьох поширених септакордів.',
        'Ритм на слух: почуй одно­тактовий малюнок над тихим пульсом і обери відповідний ритм.',
        'Кожна вправа зі слуху рахується за точністю й живить той самий облік прогресу, що й вправа на грифі — те, що ти даєш важче, повертається на повтор.'] },
  { v:'2.0.0', date:'2026-06-20',
    en:['Euterpe now has a Practice mode. A new navigation layer switches between Reference — the chords, scales and circle you already know — and Practice, so the reference tabs stay uncluttered as practice grows (on a phone it lives in a thumb-friendly bar along the bottom).',
        'The first drill: fretboard note-naming. Euterpe names a note and you tap every place it lives on the neck — correct taps light up and sound, wrong ones buzz. It is scored on accuracy and timed only for pace.',
        'Euterpe now remembers how you are doing. A learner model tracks each note you practise, resurfaces the ones you miss, and shows your progress — accuracy, best streak and sessions — on the Practice screen.',
        'Jump straight from the Notes view into the drill with "Drill on the neck".'],
    uk:['У Euterpe зʼявився режим «Практика». Новий рівень навігації перемикає між «Довідником» — акорди, гами й коло квінт, які ти вже знаєш — і «Практикою», тож вкладки довідника лишаються охайними, поки практика росте (на телефоні він живе у зручній для великого пальця смужці внизу).',
        'Перша вправа: називання нот на грифі. Euterpe називає ноту, а ти позначаєш усі місця, де вона живе на грифі — правильні дотики світяться і звучать, хибні гудуть. Рахунок ведеться за точністю, а час — лише для темпу.',
        'Euterpe тепер памʼятає твої успіхи. Модель учня відстежує кожну ноту, яку ти тренуєш, повертає ті, що даються важче, і показує прогрес — точність, найкращу серію та кількість сесій — на екрані «Практики».',
        'Переходь просто з виду «Ноти» до вправи кнопкою «Тренувати на грифі».'] },
  { v:'1.27.2', date:'2026-06-19',
    en:['Landscape now matches portrait: the same compact colour key applies, and the chord-shapes card keeps its proper place beside the neck instead of dropping to the bottom of the page.'],
    uk:['Альбомна орієнтація тепер відповідає книжковій: застосовується та сама компактна легенда, а картка форм акорду лишається на своєму місці поруч із грифом, а не падає в самий низ сторінки.'] },
  { v:'1.27.1', date:'2026-06-19',
    en:['The chord-shapes card now opens with just the first few shapes — the open shape and the nearest forms — and a "More shapes" button reveals the rest of the library when you want them, so the card no longer floods a phone with diagrams.',
        'The note-colour key under the neck is tidier on phones: it now fits a single clean row (the degree numbers tuck away on small screens) instead of wrapping into a second line that looked like part of the neck\'s scroll.'],
    uk:['Картка форм акорду тепер відкривається лише з кількома першими формами — відкритою та найближчими — а кнопка «Більше форм» показує решту бібліотеки, коли вони потрібні, тож картка більше не засипає телефон діаграмами.',
        'Кольорова легенда нот під грифом охайніша на телефоні: тепер вона вміщується в один рядок (номери ступенів ховаються на малих екранах) замість того, щоб переноситися на другий рядок, який виглядав частиною прокрутки грифа.'] },
  { v:'1.27.0', date:'2026-06-19',
    en:['The links between the tabs now go both ways. In Scales, once you overlay one of the key\'s chords on the neck, an "Open in chords" button jumps you straight to that chord in the Chords view — so the diatonic-chord row is no longer a dead end.',
        'The Circle of fifths gains an "Open in chords" button beside "Open in scales", so you can jump from a key straight to its tonic chord on the neck.'],
    uk:['Звʼязки між вкладками тепер працюють в обидва боки. У «Гамах», коли ти накладаєш один з акордів тональності на гриф, кнопка «Відкрити в акордах» одразу переносить до цього акорду у вкладці «Акорди» — тож ряд акордів тональності більше не глухий кут.',
        'У «Колі квінт» зʼявилася кнопка «Відкрити в акордах» поруч із «Відкрити в гамах» — тож від тональності можна одразу перейти до її тонічного акорду на грифі.'] },
  { v:'1.26.0', date:'2026-06-19',
    en:['The chord-shapes card now shows a fuller set of ways to play each chord — the open shape, the barre forms, and several movable shapes higher up the neck — so it reads as a shape library instead of one or two lonely diagrams.',
        'You can fold the chord shapes away: a − on the card collapses it when you don\'t need it, and it remembers whether you left it open or closed.',
        'On a phone the chord shapes now sit right under the neck — before the "what to play over this" panel — so "how to play it" comes first.'],
    uk:['Картка форм акорду тепер показує більший набір способів зіграти акорд — відкриту форму, барре та кілька рухомих форм вище по грифу — тож це радше бібліотека форм, ніж одна-дві самотні діаграми.',
        'Форми акорду можна згорнути: позначка − на картці ховає її, коли вона не потрібна, і застосунок запам\'ятовує, лишив ти її відкритою чи закритою.',
        'На телефоні форми акорду тепер одразу під грифом — перед панеллю «що грати над цим» — тож «як це зіграти» йде першим.'] },
  { v:'1.25.1', date:'2026-06-18',
    en:['Chord types start simple: only the basic chords show at first, with a "more" toggle that reveals the sevenths and extended chords when you want them — so the picker is no longer a wall of twenty buttons.',
        'A bigger fretboard on desktop: the neck now spans the full width of the page, with the "what to play over this" panel tucked up beside the controls.',
        'The Notes view is simpler: the highlighted note now follows the key you pick above, and a single "Naturals only" switch replaces the old grid of note buttons.',
        'A tidier toolbar on phones: the metronome and backing band now tuck behind a "Backing" button next to Settings, and the view / key / display controls are no longer boxed in — so the header is lighter and the neck sits higher.',
        'Fixed a glitch where the slimming header could strand a control mid-row as you scrolled on a phone.'],
    uk:['Типи акордів починаються з простого: спершу показано лише базові акорди, а перемикач «більше» відкриває септакорди та розширені, коли вони потрібні — тож вибір більше не стіна з двадцяти кнопок.',
        'Більший гриф на комп\'ютері: гриф тепер займає всю ширину сторінки, а панель «що грати над цим» перемістилася вгору поруч із керуванням.',
        'Вид «Ноти» простіший: підсвічена нота тепер іде за тонікою, яку ти вибираєш вище, а один перемикач «Тільки натуральні» замінює стару сітку кнопок із нотами.',
        'Охайніша панель на телефонах: метроном і супровід тепер ховаються за кнопкою «Супровід» поруч із «Налаштуваннями», а керування видом / тонікою / показом більше не в рамці — тож шапка легша, а гриф сидить вище.',
        'Виправлено збій, коли шапка, що стискається, могла лишити елемент керування посеред ряду під час гортання на телефоні.'] },
  { v:'1.25.0', date:'2026-06-18',
    en:['A wider, more readable fretboard on desktop: on a large screen the neck now grows with the window — taller string spacing and bigger note dots — instead of stretching into a thin strip.',
        'Keyboard shortcuts on desktop: Space to listen or stop, L to loop, M for the metronome, 1–3 to switch tabs, A–G to set the key, and [ / ] to transpose it by a semitone. Press ? (or the link below the page) for the full list.',
        'Landscape is finally useful: turn your phone sideways and the screen splits in two — the controls, chord cards and progression scroll on the left while the neck stays pinned on the right, always in view.',
        'A cleaner first look: each view\'s description and the board\'s playing tip now tuck behind a ? next to the heading — on every screen, not just phones — so the controls and the neck sit higher; tap ? whenever you want the explanation back.',
        'A clearer hint that the chord rows scroll: when a row of chord types runs off the edge of a phone screen, it now fades at the right so you can tell there is more to swipe to.'],
    uk:['Ширший і чіткіший гриф на комп\'ютері: на великому екрані гриф тепер росте разом із вікном — більша відстань між струнами й більші крапки нот — замість того щоб розтягуватися у вузьку смужку.',
        'Гарячі клавіші на комп\'ютері: Space — прослухати чи зупинити, L — луп, M — метроном, 1–3 — перемикати вкладки, A–G — задати тоніку, [ / ] — транспонувати її на півтон. Натисни ? (або посилання під сторінкою), щоб побачити весь список.',
        'Альбомна орієнтація нарешті корисна: поверни телефон боком — і екран ділиться навпіл: керування, картки акордів і прогресія гортаються ліворуч, а гриф лишається закріпленим праворуч, завжди в полі зору.',
        'Чистіший перший погляд: опис кожного виду й підказка для гри на грифі тепер ховаються за позначкою ? біля заголовка — на кожному екрані, не лише на телефонах — тож керування й гриф сидять вище; натисни ?, коли захочеш повернути пояснення.',
        'Чіткіший натяк, що ряди акордів гортаються: коли ряд типів акордів виходить за край екрана телефона, він тепер згасає праворуч, тож видно, що є куди гортнути.'] },
  { v:'1.24.0', date:'2026-06-17',
    en:['Mobile shell pass — less scrolling, the neck always in reach. On phones the fretboard now stays pinned in view while you scroll the chords, cards and progression below it, and gently snaps back into place — so you can pick a chord or chip and see it on the neck without scrolling back up.',
        'Shorter control stack: each view\'s description now tucks behind an ⓘ on the heading, and the chord/quality rows swipe sideways instead of stacking into tall blocks — so the board sits higher on a phone.',
        'The header now slims as you scroll, keeping the tabs and playback controls within reach at the top instead of scrolling away.',
        'Your phone no longer sleeps while a loop, metronome or progression is playing, and an accidental over-scroll can no longer reload the app mid-jam.'],
    uk:['Шліфування для телефонів — менше гортання, гриф завжди під рукою. На телефонах гриф тепер лишається закріпленим у полі зору, поки ти гортаєш акорди, картки та прогресію під ним, і мʼяко повертається на місце — тож можна обрати акорд чи фішку й одразу побачити їх на грифі, не гортаючи назад угору.',
        'Коротший стос керування: опис кожного виду тепер ховається за позначкою ⓘ біля заголовка, а ряди акордів/типів гортаються вбік замість того, щоб складатися у високі блоки — тож гриф на телефоні сидить вище.',
        'Шапка тепер стискається під час гортання, тримаючи вкладки та керування відтворенням під рукою вгорі, а не зникаючи з екрана.',
        'Телефон більше не засинає, поки грає луп, метроном чи прогресія, а випадкове перегортання вже не може перезавантажити застосунок посеред гри.'] },
  { v:'1.23.0', date:'2026-06-17',
    en:['Install Euterpe straight from the app: where your browser supports it, an "Install" button now appears in the header, so you can add Euterpe to your device without digging through browser menus. (On iPhone, keep using Share → Add to Home Screen.)',
        'Update notifications: when a new version is ready, a small prompt now offers to reload into it — so an already-open tab no longer keeps running the old version until you happen to refresh.',
        'Smoother progression playback: the fretboard no longer re-fades all its dots on every chord change while a progression is playing.'],
    uk:['Встановлення прямо із застосунку: якщо твій браузер це підтримує, у шапці зʼявляється кнопка «Встановити», тож Euterpe можна додати на пристрій, не порпаючись у меню браузера. (На iPhone — як і раніше, через «Поділитися» → «На початковий екран».)',
        'Сповіщення про оновлення: коли готова нова версія, невелика підказка пропонує перезавантажитись у неї — тож відкрита вкладка більше не працює на старій версії, доки ти випадково не оновиш сторінку.',
        'Плавніше відтворення прогресії: точки на грифі більше не згасають наново на кожній зміні акорду, поки грає прогресія.'] },
  { v:'1.22.1', date:'2026-06-17',
    en:['Installed-app polish for iPhone: adding Euterpe to your home screen now opens it in its own dark, full-screen window with the proper app name and a matching status bar, instead of a generic browser-style shell.',
        'On phones with a camera notch or a home-indicator bar, the layout now keeps clear of them, so nothing hides behind the cut-out edges when the app runs full-screen.'],
    uk:['Шліфування встановленого застосунку для iPhone: додавання Euterpe на головний екран тепер відкриває його у власному темному повноекранному вікні з правильною назвою застосунку та відповідним рядком стану, а не в загальному вигляді браузера.',
        'На телефонах із вирізом під камеру чи смугою-індикатором унизу макет тепер тримається від них на відстані, тож у повноекранному режимі нічого не ховається за краями екрана.'] },
  { v:'1.22.0', date:'2026-06-17',
    en:['Euterpe is now installable. Add it to your phone\'s home screen or your desktop and it opens in its own window — no browser bar — and keeps working with no connection.',
        'New app icon: the guitar inside a Greek-key (meander) border, a nod to Euterpe, the Greek muse of music.'],
    uk:['Euterpe тепер можна встановити. Додай застосунок на головний екран телефона чи на робочий стіл — він відкриється у власному вікні, без панелі браузера, і працюватиме без інтернету.',
        'Нова іконка застосунку: гітара в обрамленні грецького меандра — відсилання до Евтерпи, грецької музи музики.'] },
  { v:'1.21.1', date:'2026-06-17',
    en:['Fixed: on the Arpeggio and Identify views, the fretboard now updates straight away when you change the tuning, capo, fret window or handedness — previously it kept its old layout on those two views until you switched away and back.'],
    uk:['Виправлено: у видах «Арпеджіо» та «Розпізнати» гриф тепер одразу оновлюється, коли ти змінюєш стрій, каподастр, діапазон ладів чи ліворукість — раніше на цих двох видах він лишався зі старим виглядом, доки ти не перемкнешся на інший вид і назад.'] },
  { v:'1.21.0', date:'2026-06-17',
    en:['The app is now called Euterpe — after the Greek muse of music. "Guitar studio" stays on as a descriptor; nothing about how the app works has changed.',
        'Scales view now colours the fifth and the seventh, not just the root and third.',
        'Each scale shows its tonic-seventh skeleton — root, third, fifth, seventh — in the same colours used across the chord and triad views, with the remaining passing tones (2 · 4 · 6) in a neutral tone. The fifth is finally named in the legend instead of blending into a generic "other" that had borrowed the fifth’s blue.',
        'The legend now lists only the degrees the selected scale actually contains, so a pentatonic with no seventh no longer shows a seventh swatch.'],
    uk:['Застосунок тепер називається Euterpe — на честь грецької музи музики. «Гітарна студія» лишається описом; у роботі застосунку нічого не змінилося.',
        'Вид «Гами» тепер фарбує квінту й септиму, а не лише тоніку й терцію.',
        'Кожна гама показує свій каркас — тоніка, терція, квінта, септима — тими самими кольорами, що й види акордів і тріад, а решта прохідних нот (2 · 4 · 6) — нейтральним тоном. Квінту нарешті названо в легенді, замість того щоб зливатися із загальним «іншим», який позичав її синій колір.',
        'Легенда тепер перелічує лише ті ступені, які справді є в обраній гамі, тож пентатоніка без септими більше не показує позначку септими.'] },
  { v:'1.20.0', date:'2026-06-16',
    en:['Phase 2 — completing the reference: arpeggios, a capo, and the CAGED framework, added without crowding the three-tab layout.',
        'New "Arpeggio" view under Chords / triads: the same chord, shown as a melodic shape you run up the neck. Listen plays it ascending, and you can isolate one position as a practice box — the bridge between a chord and the scale you solo with over it.',
        'Capo: a new control in Settings (next to Tuning and Frets). Set a capo and the fretboard dims the frets behind it and marks the capo as a movable nut, so you can see where your shapes sit — the notes themselves don\'t move.',
        'CAGED: in the major scale, the five fretboard positions are now labelled with their C·A·G·E·D chord shapes (E·D·C·A·G up the neck) instead of plain numbers, and the panel names the chord form each scale box is built around — making the link between chord shapes and scale positions explicit.'],
    uk:['Фаза 2 — доповнюємо довідник: арпеджіо, каподастр і система CAGED, додані без захаращення тривкладкового макета.',
        'Новий вид «Арпеджіо» поряд з «Акордами / тріадами»: той самий акорд, показаний як мелодична форма, яку ти ведеш угору по грифу. «Прослухати» грає його висхідно, а одну позицію можна ізолювати як бокс для практики — місток між акордом і гамою, якою ти граєш над ним.',
        'Каподастр: нове керування в «Налаштуваннях» (поряд зі «Строєм» і «Ладами»). Постав каподастр — і гриф приглушить лади за ним і позначить каподастр як рухомий поріжок, тож видно, де лягають форми; самі ноти не зсуваються.',
        'CAGED: у мажорній гамі п’ять позицій на грифі тепер підписані формами акордів C·A·G·E·D (E·D·C·A·G угору по грифу) замість простих номерів, а панель називає форму акорду, навколо якої побудований кожен бокс гами, — роблячи зв’язок між формами акордів і позиціями гами явним.'] },
  { v:'1.19.0', date:'2026-06-16',
    en:['Clarity pass: the same tools, less clutter — and the fretboard front and centre.',
        'The neck now sits directly under the controls. The chord-shape cards and the progression sequencer moved below the board, so on a phone you reach the fretboard right after picking a chord instead of scrolling past everything first.',
        'The chord picker is grouped into Basic / Sevenths / Extended tiers, so the 21 chord types read as organised sections instead of one long wall of buttons.',
        'The timing bar is tidier: the metronome, bass and drums are collected into one labelled "Backing" group, so the bar reads as a few clusters rather than a row of loose buttons.',
        'Backing that starts itself: turning on Bass or Drums now starts the chord loop when nothing is playing, so they behave like the metronome instead of staying silent until you start a loop or progression first.',
        'Fewer control layers: the view switch (chord tones / triad shapes / identify, or scale / notes) moved up next to the root, so each tab shows one "View · Root · Display" header instead of a separate row above the board; the dot-label toggle is now "Names / Intervals" so it no longer reads as a second "Notes".',
        '"Play over this" where you need it: on a phone the suggestion panel now sits directly under the fretboard instead of at the very bottom of the page, below the chord shapes and the progression builder.',
        'Smaller polish: on a narrow screen the tab strip now fades at its right edge to show more tabs scroll off-screen, and the root / note-name separator no longer strands itself on its own line when the controls wrap.'],
    uk:['Прохід на ясність: ті самі інструменти, менше безладу — і гриф у центрі уваги.',
        'Гриф тепер одразу під керуванням. Картки форм акорду та секвенсор прогресії переїхали під гриф, тож на телефоні ти потрапляєш на гриф одразу після вибору акорду, а не прогортуєш усе перед тим.',
        'Вибір акорду згруповано в рівні «Базові / Септакорди / Розширені», тож 21 тип акорду читається як впорядковані секції, а не суцільна стіна кнопок.',
        'Панель темпу охайніша: метроном, бас і ударні зібрано в одну підписану групу «Супровід», тож панель читається як кілька кластерів, а не ряд розрізнених кнопок.',
        'Супровід, що сам запускається: увімкнення «Бас» чи «Ударні» тепер запускає луп акорду, коли нічого не грає, тож вони поводяться як метроном, а не мовчать, доки спершу не запустиш луп чи прогресію.',
        'Менше шарів керування: перемикач виду (тони акорду / форми тріад / розпізнати чи гама / ноти) переїхав угору, поряд із тонікою, тож кожна вкладка показує один заголовок «Вид · Тоніка · Показ» замість окремого рядка над грифом; перемикач підпису крапок тепер «Назви / Інтервали», тож він більше не читається як друге «Ноти».',
        '«Що грати над цим» там, де треба: на телефоні панель підказок тепер одразу під грифом, а не в самому низу сторінки під формами акорду та секвенсором.',
        'Дрібні штрихи: на вузькому екрані смужка вкладок тепер згасає праворуч, показуючи, що частина вкладок ховається за краєм, а роздільник між тонікою й назвами нот більше не лишається сам на окремому рядку, коли керування переноситься.'] },
  { v:'1.18.0', date:'2026-06-16',
    en:['Feel pass (Phase 1d): subtle, motion-respecting animation that makes sound and rhythm visible.',
        'Beat pulse — while a loop or the backing band plays, the transport indicator now pumps on every beat (a stronger pulse on the downbeat), locked to the same precise clock as the sound, so you can see the tempo.',
        'Pluck ripple — tapping a note on the fretboard sends a one-shot halo out from the dot, so a pluck reads as sound emanating.',
        'Smoother board changes — when you change key, chord or scale the fretboard dots now fade in with a quick left-to-right sweep instead of snapping, so a re-draw reads as a transition.',
        'Circle of fifths — picking a key now draws a connecting arc through the subdominant, tonic and dominant, turning the recolour into a visible harmonic relationship.',
        'All of the above is disabled automatically if your system prefers reduced motion, and the timing-bar controls were aligned to a common height so they stay tidy at any browser zoom.'],
    uk:['Прохід «відчуття» (Фаза 1d): делікатна анімація, що поважає налаштування руху й робить звук і ритм видимими.',
        'Пульс долі — поки грає луп чи супровідний гурт, індикатор транспорту тепер пульсує на кожній долі (сильніше на сильній долі), синхронно з тим самим точним годинником, що й звук, — тож темп можна побачити.',
        'Брижі від щипка — дотик до ноти на грифі пускає від крапки одноразове кільце, тож щипок читається як звук, що розходиться.',
        'Плавніші зміни на грифі — коли ти змінюєш тональність, акорд чи гаму, крапки тепер плавно з’являються хвилею зліва направо замість різкого стрибка.',
        'Квінтове коло — вибір тональності тепер малює дугу через субдомінанту, тоніку й домінанту, перетворюючи перефарбування на видимий гармонічний зв’язок.',
        'Усе це автоматично вимикається, якщо у системі ввімкнено зменшений рух, а елементи панелі темпу вирівняно за спільною висотою, щоб вони лишалися охайними за будь-якого масштабу браузера.'] },
  { v:'1.17.0', date:'2026-06-16',
    en:['New "Identify" view under Chords / Triads: tap the notes you are playing on the neck and the app names the chord — including the real alternatives (e.g. C6 and Am7 are the same notes) and slash chords when the bass note is not the root.',
        'When the notes don\'t fit any chord exactly, Identify now shows the closest matches instead of just "unknown" — naming the chord you are one or two notes away from and telling you which tone is missing or extra.',
        'The sidebar is now a live "Play over this" panel instead of a static table: for the chord you are looking at it shows the arpeggio and the scales that fit, and tapping a scale jumps you straight to it.'],
    uk:['Новий вид «Розпізнати» поряд з «Акордами / тріадами»: натисни на грифі ноти, які береш, — і програма назве акорд, разом зі справжніми варіантами (напр., C6 і Am7 — це ті самі ноти) та слеш-акордами, коли в басі не тоніка.',
        'Коли ноти не складають жодного акорду точно, «Розпізнати» тепер показує найближчі варіанти замість простого «невідомо» — називає акорд, до якого бракує однієї-двох нот, і вказує, якої ноти бракує чи яка зайва.',
        'Бічна панель тепер жива — «Що грати над цим» замість статичної таблиці: для акорду, який ти розглядаєш, вона показує арпеджіо та гами, що підходять, а дотик до гами одразу веде до неї.'] },
  { v:'1.16.0', date:'2026-06-16',
    en:['One fretboard instead of four: the chord-tones, triads, scale and notes views now share a single neck that just changes what it highlights, so switching views keeps the board steady in front of you.',
        'Fewer tabs: "Notes on the neck" moved from its own tab into a Notes view inside Scales (next to Scale), the same way Chords and Triads sit together under one tab.',
        'Tidier controls: the selectors above the neck were grouped into a more compact area.'],
    uk:['Один гриф замість чотирьох: види «тони акорду», «тріади», «гама» та «ноти» тепер мають спільний гриф, який лише змінює підсвічування, тож перемикання видів не зрушує гриф перед тобою.',
        'Менше вкладок: «Ноти на грифі» переїхали зі своєї вкладки у вид «Ноти» всередині «Гам» (поряд із «Гамою») — так само, як «Акорди» і «Тріади» живуть під однією вкладкою.',
        'Охайніше керування: селектори над грифом згруповано в компактнішу зону.'] },
  { v:'1.15.0', date:'2026-06-16',
    en:['Pick your key once and the whole app follows: choosing a root — or a key on the circle of fifths — now switches the chords, scales, circle and notes views together, instead of each tab keeping its own separate key.',
        'The circle of fifths is now tied to your current key: it always highlights the key you are in and its closest neighbours, and tapping any key on it sets that key everywhere.'],
    uk:['Обери тональність один раз — і вся програма слідує за нею: вибір тоніки чи тональності на квінтовому колі тепер одночасно перемикає акорди, гами, коло та ноти, замість того щоб кожна вкладка тримала свою окрему тональність.',
        'Квінтове коло тепер прив’язане до твоєї поточної тональності: воно завжди підсвічує тональність, у якій ти перебуваєш, та її найближчих сусідів, а дотик до будь-якої тональності на колі встановлює її всюди.'] },
  { v:'1.14.0', date:'2026-06-15',
    en:['The drums now have a backbeat: a snare lands on beats 2 and 4, so turning on Drums sounds like a real groove instead of a ticking pulse.',
        'Listen now plays at a fixed, comfortable speed no matter your tempo — so slowing the metronome down for practice no longer makes the preview crawl. Loop and progression Play still follow the tempo, since they are backings you play over.'],
    uk:['Удар­ні тепер мають бекбіт: малий барабан звучить на 2-й і 4-й долях, тож увімкнені «Ударні» звучать як справжній грув, а не як цокання.',
        '«Прослухати» тепер грає зі сталою зручною швидкістю незалежно від темпу — тож сповільнення метронома для занять більше не робить попереднє відтворення млявим. «Луп» і «Програти» прогресію, як і раніше, слідують за темпом, бо це супровід, під який ти граєш.'] },
  { v:'1.13.0', date:'2026-06-15',
    en:['Easier to use on phones: fretboard notes and buttons now have bigger touch targets, and tapping a note no longer triggers zoom or selects text.',
        'The interface accent is now a distinct teal, so a selected control is no longer the same blue as the "fifth" note on the fretboard.',
        'The fretboard now shows position-marker inlays on its face — single dots at frets 3·5·7·9 and a double at 12 — so you can orient at a glance.',
        'Chord and triad diagrams now print a suggested fingering (1–4) inside each dot.',
        'The neck fades at its right edge when more frets are scrollable off-screen, and the fret wires gained a subtle metallic sheen.'],
    uk:['Зручніше на телефонах: ноти на грифі та кнопки тепер мають більші зони дотику, а дотик до ноти більше не викликає масштабування чи виділення тексту.',
        'Акцентний колір інтерфейсу тепер окремий бірюзовий, тож вибраний елемент більше не збігається із синім кольором «квінти» на грифі.',
        'На грифі з’явилися маркери позицій — поодинокі крапки на ладах 3·5·7·9 і подвійна на 12 — щоб орієнтуватися з першого погляду.',
        'Діаграми акордів і тріад тепер показують підказку аплікатури (1–4) всередині кожної крапки.',
        'Гриф плавно згасає біля правого краю, коли є ще лади для прокрутки, а лади отримали легкий металевий відблиск.'] },
  { v:'1.12.0', date:'2026-06-15',
    en:['Chord diagrams now show every common way to play the chord — the open shape plus the E-shape and A-shape barre forms — instead of just one.',
        'Tap a voicing card to select it: Listen and Loop then play that exact shape in its real register, so an open chord and its barre version actually sound different.',
        'Chord-card dots are now live — click one to hear that string — and are coloured by their role in the chord (root, third, fifth…).',
        'Triads now have shape cards too, one per inversion, matching the chord view.',
        'You can finally loop a triad as a backing track, and Listen plays the inversion and string set you are actually looking at — with the bass following the triad\u2019s correct fifth.',
        'Strums now sweep across the strings instead of sounding all at once.'],
    uk:['Діаграми акордів тепер показують усі звичні способи зіграти акорд — відкриту форму та барре у формі E і A — а не лише одну.',
        'Натисни картку аплікатури, щоб обрати її: «Прослухати» і «Луп» зіграють саме цю форму у її реальному регістрі, тож відкритий акорд і барре справді звучать по-різному.',
        'Крапки на картці акорду тепер активні — натисни, щоб почути цю струну — і пофарбовані за роллю в акорді (тоніка, терція, квінта…).',
        'Тріади тепер теж мають картки форм — по одній на кожне обернення, як у виді акордів.',
        'Нарешті можна зациклити тріаду як супровід, а «Прослухати» грає те обернення й набір струн, які ти бачиш — із басом за правильною квінтою тризвуку.',
        'Бій тепер «прокочується» по струнах, а не звучить усіма нотами одночасно.'] },
  { v:'1.11.0', date:'2026-06-15',
    en:['Playback controls are clearer: Listen and Loop now sit together in the timing bar, so hearing the current chord once (Listen) and looping it as a backing (Loop) are one obvious pair.',
        'Loop now appears only on the chord-tones view where it applies; the transport chip is still there to stop playback from any tab.',
        'The fretboard fits phones: a windowed fret range now scales to the screen with no sideways scrolling — only the full "All frets" view still scrolls. It re-fits when you rotate.',
        'Sturdier on unusual browsers: if a browser has no audio support, the playback buttons are disabled with a note instead of doing nothing.'],
    uk:['Керування відтворенням зрозуміліше: «Прослухати» і «Луп» тепер поруч у панелі темпу — почути поточний акорд один раз (Прослухати) та зациклити його як супровід (Луп) стали однією очевидною парою.',
        '«Луп» з’являється лише у вкладі тонів акорду, де він діє; чип транспорту, як і раніше, зупиняє відтворення з будь-якої вкладки.',
        'Гриф вміщується на телефонах: віконний діапазон ладів тепер масштабується під екран без бічної прокрутки — гортається лише повний вид «Усі лади». Підлаштовується при повороті.',
        'Надійніше на незвичних браузерах: якщо браузер не підтримує звук, кнопки відтворення вимикаються з підказкою, а не лишаються «мертвими».'] },
  { v:'1.10.0', date:'2026-06-14',
    en:['Backing now plays as a band: turn on Bass and Drums in the timing bar and the loop or progression becomes a jam-along bed for improvising over.',
        'A synthesized bass follows each chord — root on beat 1, the chord\u2019s fifth on beat 3 — and sits cleanly under the guitar.',
        'An optional groove adds a kick on beats 1 and 3 with steady 8th-note hi-hats, accented on the downbeat.',
        'The guitar comping is more human now: small note-to-note changes in loudness and timing, plus a softer push on beat 3 when the band is on.',
        'Your Bass and Drums choices are remembered across reloads.'],
    uk:['\u0421\u0443\u043f\u0440\u043e\u0432\u0456\u0434 \u0442\u0435\u043f\u0435\u0440 \u0437\u0432\u0443\u0447\u0438\u0442\u044c \u044f\u043a \u0433\u0443\u0440\u0442: \u0443\u0432\u0456\u043c\u043a\u043d\u0438 \u00ab\u0411\u0430\u0441\u00bb \u0456 \u00ab\u0423\u0434\u0430\u0440\u043d\u0456\u00bb \u0443 \u043f\u0430\u043d\u0435\u043b\u0456 \u0442\u0435\u043c\u043f\u0443 \u2014 \u0456 \u043b\u0443\u043f \u0447\u0438 \u043f\u0440\u043e\u0433\u0440\u0435\u0441\u0456\u044f \u0441\u0442\u0430\u044e\u0442\u044c \u043c\u0456\u043d\u0443\u0441\u0456\u0432\u043a\u043e\u044e \u0434\u043b\u044f \u0456\u043c\u043f\u0440\u043e\u0432\u0456\u0437\u0430\u0446\u0456\u0457.',
        '\u0421\u0438\u043d\u0442\u0435\u0437\u043e\u0432\u0430\u043d\u0438\u0439 \u0431\u0430\u0441 \u0441\u043b\u0456\u0434\u0443\u0454 \u0437\u0430 \u043a\u043e\u0436\u043d\u0438\u043c \u0430\u043a\u043e\u0440\u0434\u043e\u043c \u2014 \u0442\u043e\u043d\u0456\u043a\u0430 \u043d\u0430 \u043f\u0435\u0440\u0448\u0456\u0439 \u0434\u043e\u043b\u0456, \u043a\u0432\u0456\u043d\u0442\u0430 \u043d\u0430 \u0442\u0440\u0435\u0442\u0456\u0439 \u2014 \u0456 \u0447\u0438\u0441\u0442\u043e \u043b\u044f\u0433\u0430\u0454 \u043f\u0456\u0434 \u0433\u0456\u0442\u0430\u0440\u0443.',
        '\u0414\u043e\u0434\u0430\u0442\u043a\u043e\u0432\u0438\u0439 \u0433\u0440\u0443\u0432: \u0431\u043e\u0447\u043a\u0430 \u043d\u0430 1-\u0448\u0456\u0439 \u0456 3-\u0439 \u0434\u043e\u043b\u044f\u0445 \u0442\u0430 \u0440\u0456\u0432\u043d\u0456 \u0432\u043e\u0441\u044c\u043c\u0456 \u0445\u0430\u0439-\u0445\u0435\u0442\u0430 \u0437 \u0430\u043a\u0446\u0435\u043d\u0442\u043e\u043c \u043d\u0430 \u0441\u0438\u043b\u044c\u043d\u0456\u0439 \u0434\u043e\u043b\u0456.',
        '\u0413\u0456\u0442\u0430\u0440\u043d\u0438\u0439 \u0430\u043a\u043e\u043c\u043f\u0430\u043d\u0435\u043c\u0435\u043d\u0442 \u0436\u0438\u0432\u0456\u0448\u0438\u0439: \u043d\u0435\u0432\u0435\u043b\u0438\u043a\u0456 \u0437\u043c\u0456\u043d\u0438 \u0433\u0443\u0447\u043d\u043e\u0441\u0442\u0456 \u0439 \u0447\u0430\u0441\u0443 \u043c\u0456\u0436 \u043d\u043e\u0442\u0430\u043c\u0438 \u0442\u0430 \u043c\u2019\u044f\u043a\u0456\u0448\u0438\u0439 \u0443\u0434\u0430\u0440 \u043d\u0430 3-\u0439 \u0434\u043e\u043b\u0456, \u043a\u043e\u043b\u0438 \u0433\u0443\u0440\u0442 \u0443\u0432\u0456\u043c\u043a\u043d\u0435\u043d\u043e.',
        '\u0412\u0438\u0431\u0456\u0440 \u00ab\u0411\u0430\u0441\u00bb \u0456 \u00ab\u0423\u0434\u0430\u0440\u043d\u0456\u00bb \u0437\u0431\u0435\u0440\u0456\u0433\u0430\u0454\u0442\u044c\u0441\u044f \u043f\u0456\u0441\u043b\u044f \u043f\u0435\u0440\u0435\u0437\u0430\u0432\u0430\u043d\u0442\u0430\u0436\u0435\u043d\u043d\u044f.'] },
  { v:'1.9.0', date:'2026-06-14',
    en:['Playback timing was rebuilt on a precise audio clock, so the metronome, loop and progression no longer drift out of time — especially on phones and in background tabs.',
        'The tempo slider now glides smoothly while something is playing, instead of restarting the beat.',
        'The lit notes during the loop and progression now stay locked to the sound.',
        'Groundwork for the upcoming practice modes: separate internal audio channels and short correct / wrong / count-in cue sounds.'],
    uk:['Тайминг відтворення перебудовано на точному аудіогодиннику — метроном, луп і прогресія більше не «пливуть» у часі, особливо на телефонах і у фонових вкладках.',
        'Повзунок темпу тепер плавно змінює швидкість під час гри, а не перезапускає долю.',
        'Підсвічені ноти під час лупа та прогресії тепер точно збігаються зі звуком.',
        'Основа для майбутніх режимів тренування: окремі внутрішні аудіоканали та короткі звуки-підказки правильно / помилка / відлік.'] },
  { v:'1.8.0', date:'2026-06-14',
    en:['The guitar tone was reworked to sound more like a real instrument.',
        'Notes now ring through a body resonance, so they sound like they come from a guitar body rather than a bare synthesized string.',
        'Tuning is accurate across the whole neck \u2014 high notes no longer drift slightly flat.',
        'Plucking responds to dynamics: harder is louder and brighter, with subtle note-to-note variation so long loops feel less robotic.',
        'Low and high strings now have their own character \u2014 darker, longer-ringing bass and rounder treble.'],
    uk:['\u0422\u0435\u043c\u0431\u0440 \u0433\u0456\u0442\u0430\u0440\u0438 \u043f\u0435\u0440\u0435\u0440\u043e\u0431\u043b\u0435\u043d\u043e, \u0449\u043e\u0431 \u0432\u0456\u043d \u0437\u0432\u0443\u0447\u0430\u0432 \u0431\u043b\u0438\u0436\u0447\u0435 \u0434\u043e \u0441\u043f\u0440\u0430\u0432\u0436\u043d\u044c\u043e\u0433\u043e \u0456\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u0430.',
        '\u041d\u043e\u0442\u0438 \u0442\u0435\u043f\u0435\u0440 \u0437\u0432\u0443\u0447\u0430\u0442\u044c \u043a\u0440\u0456\u0437\u044c \u0440\u0435\u0437\u043e\u043d\u0430\u043d\u0441 \u043a\u043e\u0440\u043f\u0443\u0441\u0443 \u2014 \u043d\u0435\u043c\u043e\u0432 \u0456\u0437 \u0434\u0435\u043a\u0438 \u0433\u0456\u0442\u0430\u0440\u0438, \u0430 \u043d\u0435 \u0432\u0456\u0434 \u0433\u043e\u043b\u043e\u0457 \u0441\u0438\u043d\u0442\u0435\u0437\u043e\u0432\u0430\u043d\u043e\u0457 \u0441\u0442\u0440\u0443\u043d\u0438.',
        '\u0411\u0443\u0434\u043e\u0432\u0430 \u0442\u043e\u0447\u043d\u0430 \u043f\u043e \u0432\u0441\u044c\u043e\u043c\u0443 \u0433\u0440\u0438\u0444\u0443 \u2014 \u0432\u0438\u0441\u043e\u043a\u0456 \u043d\u043e\u0442\u0438 \u0431\u0456\u043b\u044c\u0448\u0435 \u043d\u0435 \u0437\u0430\u043d\u0438\u0436\u0443\u044e\u0442\u044c\u0441\u044f.',
        '\u0417\u0432\u0443\u043a \u0440\u0435\u0430\u0433\u0443\u0454 \u043d\u0430 \u0434\u0438\u043d\u0430\u043c\u0456\u043a\u0443: \u0441\u0438\u043b\u044c\u043d\u0456\u0448\u0438\u0439 \u0449\u0438\u043f\u043e\u043a \u2014 \u0433\u0443\u0447\u043d\u0456\u0448\u0435 \u0439 \u044f\u0441\u043a\u0440\u0430\u0432\u0456\u0448\u0435, \u0456\u0437 \u043b\u0435\u0433\u043a\u043e\u044e \u0432\u0430\u0440\u0456\u0430\u0446\u0456\u0454\u044e \u043c\u0456\u0436 \u043d\u043e\u0442\u0430\u043c\u0438, \u0449\u043e\u0431 \u0434\u043e\u0432\u0433\u0456 \u043f\u043e\u0432\u0442\u043e\u0440\u0438 \u043d\u0435 \u0437\u0432\u0443\u0447\u0430\u043b\u0438 \u043c\u0435\u0445\u0430\u043d\u0456\u0447\u043d\u043e.',
        '\u041d\u0438\u0437\u044c\u043a\u0456 \u0439 \u0432\u0438\u0441\u043e\u043a\u0456 \u0441\u0442\u0440\u0443\u043d\u0438 \u0442\u0435\u043f\u0435\u0440 \u043c\u0430\u044e\u0442\u044c \u0432\u043b\u0430\u0441\u043d\u0438\u0439 \u0445\u0430\u0440\u0430\u043a\u0442\u0435\u0440 \u2014 \u0442\u0435\u043c\u043d\u0456\u0448\u0438\u0439 \u0456 \u0434\u043e\u0432\u0448\u0438\u0439 \u0431\u0430\u0441 \u0442\u0430 \u043c\u2019\u044f\u043a\u0448\u0456 \u0432\u0438\u0441\u043e\u043a\u0456.'] },
  { v:'1.7.0', date:'2026-06-14',
    en:['Chord vocabulary expanded from 7 to 21 types — sus2/sus4, 6 and m6, m7\u266d5, dim7, add9, 9/maj9/m9, 11, 13, 7\u266d9 and the 7\u266f9 "Hendrix" chord.',
        'Extensions (6, 9, 11, 13) now have their own violet colour, and every tone is labelled by its true degree so a \u266f9 reads as \u266f9, not \u266d3.',
        'Chord diagrams now generate a playable shape for every chord automatically, instead of showing "no simple shape" for the rarer ones.',
        'You can now tab to any note on the fretboard and play it with Enter or Space.',
        'On phones the frets are narrower and open in a 5-fret window, so the neck fits the screen better.',
        'The app now remembers your full working state across reloads — chord quality, scale and position, triad set and inversion, circle selection, the highlighted note, and your built progression.'],
    uk:['\u0421\u043b\u043e\u0432\u043d\u0438\u043a \u0430\u043a\u043e\u0440\u0434\u0456\u0432 \u0440\u043e\u0437\u0448\u0438\u0440\u0435\u043d\u043e \u0437 7 \u0434\u043e 21 \u0442\u0438\u043f\u0443 \u2014 sus2/sus4, 6 \u0456 m6, m7\u266d5, dim7, add9, 9/maj9/m9, 11, 13, 7\u266d9 \u0442\u0430 \u0430\u043a\u043e\u0440\u0434 7\u266f9 (\u00ab\u0413\u0435\u043d\u0434\u0440\u0456\u043a\u0441\u00bb).',
        '\u0420\u043e\u0437\u0448\u0438\u0440\u0435\u043d\u043d\u044f (6, 9, 11, 13) \u0442\u0435\u043f\u0435\u0440 \u043c\u0430\u044e\u0442\u044c \u0444\u0456\u043e\u043b\u0435\u0442\u043e\u0432\u0438\u0439 \u043a\u043e\u043b\u0456\u0440, \u0430 \u043a\u043e\u0436\u0435\u043d \u0442\u043e\u043d \u043f\u043e\u0437\u043d\u0430\u0447\u0435\u043d\u043e \u0441\u0432\u043e\u0457\u043c \u0441\u0442\u0443\u043f\u0435\u043d\u0435\u043c, \u0442\u043e\u0436 \u266f9 \u0447\u0438\u0442\u0430\u0454\u0442\u044c\u0441\u044f \u044f\u043a \u266f9, \u0430 \u043d\u0435 \u266d3.',
        '\u0414\u0456\u0430\u0433\u0440\u0430\u043c\u0438 \u0430\u043a\u043e\u0440\u0434\u0456\u0432 \u0442\u0435\u043f\u0435\u0440 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u043d\u043e \u0431\u0443\u0434\u0443\u044e\u0442\u044c \u0430\u043f\u043b\u0456\u043a\u0430\u0442\u0443\u0440\u0443 \u0434\u043b\u044f \u0431\u0443\u0434\u044c-\u044f\u043a\u043e\u0433\u043e \u0430\u043a\u043e\u0440\u0434\u0443.',
        '\u0422\u0435\u043f\u0435\u0440 \u043c\u043e\u0436\u043d\u0430 \u043f\u0435\u0440\u0435\u0439\u0442\u0438 Tab\u2019\u043e\u043c \u0434\u043e \u0431\u0443\u0434\u044c-\u044f\u043a\u043e\u0457 \u043d\u043e\u0442\u0438 \u043d\u0430 \u0433\u0440\u0438\u0444\u0456 \u0442\u0430 \u0437\u0456\u0433\u0440\u0430\u0442\u0438 \u0457\u0457 \u043a\u043b\u0430\u0432\u0456\u0448\u0435\u044e Enter \u0430\u0431\u043e \u041f\u0440\u043e\u0431\u0456\u043b.',
        '\u041d\u0430 \u0442\u0435\u043b\u0435\u0444\u043e\u043d\u0430\u0445 \u043b\u0430\u0434\u0438 \u0432\u0443\u0436\u0447\u0456 \u0439 \u0432\u0456\u0434\u043a\u0440\u0438\u0432\u0430\u044e\u0442\u044c\u0441\u044f \u0443 \u0432\u0456\u043a\u043d\u0456 \u043d\u0430 5 \u043b\u0430\u0434\u0456\u0432 \u2014 \u0433\u0440\u0438\u0444 \u043a\u0440\u0430\u0449\u0435 \u0432\u043c\u0456\u0449\u0430\u0454\u0442\u044c\u0441\u044f \u043d\u0430 \u0435\u043a\u0440\u0430\u043d\u0456.',
        '\u0417\u0430\u0441\u0442\u043e\u0441\u0443\u043d\u043e\u043a \u0437\u0430\u043f\u0430\u043c\u2019\u044f\u0442\u043e\u0432\u0443\u0454 \u0432\u0435\u0441\u044c \u0440\u043e\u0431\u043e\u0447\u0438\u0439 \u0441\u0442\u0430\u043d \u043f\u0456\u0441\u043b\u044f \u043f\u0435\u0440\u0435\u0437\u0430\u0432\u0430\u043d\u0442\u0430\u0436\u0435\u043d\u043d\u044f \u2014 \u0442\u0438\u043f \u0430\u043a\u043e\u0440\u0434\u0443, \u0433\u0430\u043c\u0443 \u0439 \u043f\u043e\u0437\u0438\u0446\u0456\u044e, \u043d\u0430\u0431\u0456\u0440 \u0456 \u043e\u0431\u0435\u0440\u043d\u0435\u043d\u043d\u044f \u0442\u0440\u0456\u0430\u0434\u0438, \u0432\u0438\u0431\u0456\u0440 \u043d\u0430 \u043a\u043e\u043b\u0456, \u0432\u0438\u0434\u0456\u043b\u0435\u043d\u0443 \u043d\u043e\u0442\u0443 \u0442\u0430 \u0437\u0456\u0431\u0440\u0430\u043d\u0443 \u043f\u0440\u043e\u0433\u0440\u0435\u0441\u0456\u044e.'] },
  { v:'1.6.0', date:'2026-06-14',
    en:['Removed the subtitle tagline — the header is cleaner and the tabs sit higher.',
        'Added keyboard focus rings on every control and support for reduced-motion.',
        'Tabs now scroll sideways on phones instead of wrapping, plus a subtle hover on each tab.'],
    uk:['Прибрано підзаголовок — шапка чистіша, вкладки вище.',
        'Додано фокус-рамки для клавіатури на всіх кнопках і підтримку зменшеної анімації.',
        'На телефоні вкладки тепер прокручуються вбік замість переносу, плюс делікатне підсвічування при наведенні.'] },
  { v:'1.5.0', date:'2026-06-13',
    en:['Chord tones and Triads merged into one "Chords / triads" tab with a view toggle.',
        'Root and Notes/Intervals are now one shared bar across Harmony and Scales — pick a root once, it follows you.',
        'A single context-aware Play in the timing bar replaces the four separate Listen/Cadence buttons.'],
    uk:['Тони акорду і Тріади об\'єднані в одну вкладку «Акорди / тріади» з перемикачем виду.',
        'Тоніка і Ноти/Інтервали тепер спільні для Акордів і Гам — вибери тоніку раз, вона зберігається.',
        'Одна кнопка «Грати» в панелі темпу замість чотирьох окремих кнопок прослуховування.'] },
  { v:'1.4.0', date:'2026-06-13',
    en:['Loop and progression now keep playing when you switch tabs — backing-track mode.',
        'New transport in the timing bar shows what is playing and stops it from any tab.',
        'Added this changelog (tap the version badge any time).'],
    uk:['Луп і прогресія більше не зупиняються при перемиканні вкладок — режим мінусовки.',
        'Новий індикатор у панелі темпу показує, що грає, і зупиняє з будь-якої вкладки.',
        'Додано цей список змін (тисни на бейдж версії будь-коли).'] },
  { v:'1.3.0', date:'2026-06-13',
    en:['Tempo and metronome moved to an always-visible timing bar.',
        'Settings now holds instrument options only — tuning, handedness, fret range.'],
    uk:['Темп і метроном переїхали в завжди видиму панель темпу.',
        'Налаштування тепер містять лише інструмент — стрій, рукість, діапазон ладів.'] },
  { v:'1.2.0', date:'2026-06-13',
    en:['Chord progression sequencer: presets, per-chord bar counts, board follows the active chord, cycle or once.'],
    uk:['Секвенсер прогресій: пресети, кількість тактів на акорд, гриф слідує за активним акордом, цикл або один раз.'] },
  { v:'1.1.0', date:'2026-06-13',
    en:['Single-chord background loop.'],
    uk:['Фоновий луп одного акорду.'] },
  { v:'1.0.0', date:'2026-06-13',
    en:['Initial release: chord tones, triads, scales and modes, circle of fifths, notes on the neck.'],
    uk:['Перший випуск: тони акорду, тріади, гами й моди, коло квінт, ноти на грифі.'] },
];
